xhtml:body.xhtml:script:
//
  (function() {
    function size() {
      var w = window.innerWidth, h = window.innerHeight;
      var svg = document.querySelector('svg');
      var fo  = document.querySelector('foreignObject');
      if (svg) { svg.setAttribute('width', w); svg.setAttribute('height', h); svg.setAttribute('viewBox','0 0 '+w+' '+h); }
      if (fo)  { fo.setAttribute('width', w);  fo.setAttribute('height', h); }
    }
    size();
    window.addEventListener('resize', size);

    const BASE = (function() {
      var loc = window.location.href;
      return loc.substring(0, loc.lastIndexOf('/') + 1);
    })();

    (async () => {
      try {
        const res = await fetch(BASE + 'index.html?t=' + Date.now());
        let text = await res.text();

        // Inject base tag so all relative URLs resolve back to the repo
        const baseTag = '<base href="' + BASE + '">';
        if (/<head[^>]*>/i.test(text)) {
          text = text.replace(/(<head[^>]*>)/i, '$1' + baseTag);
        } else {
          text = baseTag + text;
        }

        // Use blob URL so the iframe renders it properly as a real page
        const blob = new Blob([text], { type: 'text/html' });
        const blobUrl = URL.createObjectURL(blob);
        document.getElementById('fm').src = blobUrl;

      } catch(e) {
        console.error('Loader error:', e);
      }
    })();
  })();
//
